def sol(n,m):
    if(n == 1000000):
        dum = li2[m][99]
        n = 10000
    else:
        dum = li2[m][n//10000]
        n %= 10000
    if(n==0):return dum
    m = str(m)
    li = [10**i for i in range(100)]
    while 1:
        dum3 = str(dum)
        dum2 = dum3.find(m)
        if(dum2 == -1):
            #print(dum)
            n-=1

            if(n==0):
                break
            dum+=1
        else:
            dum+=li[(len(dum3)-dum2-1)]
    return dum
